24	class PlayerRecordService {
25	    /**
26	     * Retrieves a PlayerRecord for the given Player ID, year and PlayerRecord ID.
27	     * @param playerId - The ID of the Player.
28	     * @param year - The year of the GameDay, or zero for all years.
29	     * @param gameDayId - The ID of the GameDay.
30	     * @returns A promise that resolves to the PlayerRecord if found, otherwise null.
31	     * @throws An error if there is a failure.
32	     */
33	    async get(playerId: number, year: number, gameDayId: number): Promise<PlayerRecordType | null> {
34	        const where = PlayerRecordWhereUniqueInputObjectSchema.parse({
35	            playerId_year_gameDayId: { playerId, year, gameDayId },
36	        });
37	
38	        return prisma.playerRecord.findUnique({ where });
39	    }
40	
41	    /**
42	     * Retrieves all player records from the database.
43	     * @returns {Promise<PlayerRecordType[]>} A promise that resolves to an
44	     * array of all player records.
45	     * @throws {Error} Throws an error if the database query fails.
46	     */
47	    async getAll(): Promise<PlayerRecordType[]> {
48	        return prisma.playerRecord.findMany({});
49	    }
50	
51	    /**
52	     * Retrieves the progress of the player by comparing the last recorded game
53	     * day with the most recently played game day.
54	     * @returns A promise that resolves to a tuple containing the last recorded
55	     * game day ID and the total/most recent game day ID, or null if no recently
56	     * played game data is available.
57	     * @throws Logs and rethrows any errors that occur during the database query
58	     * or service call.
59	     */
60	    async getProgress(): Promise<[number, number] | null> {
61	        const lastRecord = await prisma.playerRecord.findFirst({
62	            orderBy: {
63	                gameDayId: 'desc',
64	            },
65	        });
66	
67	        const total = await outcomeService.getLastPlayed();
68	        if (!total) return null;
69	        const lastGameDay = lastRecord ? lastRecord.gameDayId : 0;
70	
71	        return [lastGameDay, total.gameDayId];
72	    }
73	
74	    /**
75	     * Retrieves a list of distinct years from player records, filtered and
76	     * sorted according to the provided options.
77	     *
78	     * This method optimizes the retrieval of years by leveraging season enders
79	     * and filtering records accordingly. It can return only completed seasons
80	     * or all seasons up to the current date, and allows sorting by most recent
81	     * first.
82	     *
83	     * @param options - The options for filtering and sorting the years.
84	     * @param options.completed - If `true`, only includes years for completed
85	     * seasons (default: `false`).
86	     * @param options.mostRecentFirst - If `true`, sorts years in descending
87	     * order with zero values at the start; otherwise, sorts in ascending order
88	     * with zero values at the end (default: `false`).
89	     * @returns A promise that resolves to an array of distinct years, filtered
90	     * and sorted as specified.
91	     * @throws Will throw an error if the retrieval or processing fails.
92	     */
93	    async getAllYears({
94	        completed = false,
95	        mostRecentFirst = false,
96	    }): Promise<number[]> {
97	        let lastGamesEachYear = await prisma.gameDay.groupBy({
98	            by: ['year'],
99	            where: {
100	                game: true,
101	            },
102	            _max: {
103	                id: true,
104	            },
105	        });
106	
107	        if (completed) {
108	            const yearsWithUnplayedGames = await prisma.gameDay.groupBy({
109	                by: ['year'],
110	                where: {
111	                    game: true,
112	                    date: { gt: new Date() },
113	                },
114	            });
115	
116	            const yearsToRemove = new Set(yearsWithUnplayedGames.map(y => y.year));
117	            lastGamesEachYear = lastGamesEachYear.filter(r => !yearsToRemove.has(r.year));
118	        }
119	
120	        const years = lastGamesEachYear.map((r) => r.year);
121	
122	        return mostRecentFirst ?
123	            [0, ...years.sort((a, b) => b - a)] :
124	            [...years.sort((a, b) => a - b), 0];
125	    }
126	
127	    /**
128	     * Retrieves playerRecords by GameDay ID.
129	     * @param gameDayId - The ID of the GameDay.
130	     * @param year - The year to filter by (optional) - zero means all-time.
131	     * @returns A promise that resolves to an array of PlayerRecords or null.
132	     * @throws An error if there is a failure.
133	     */
134	    async getByGameDay(gameDayId: number, year?: number): Promise<PlayerRecordType[]> {
135	        return prisma.playerRecord.findMany({
136	            where: {
137	                gameDayId: gameDayId,
138	                ...(year != undefined ? { year: year } : {}),
139	            },
140	        });
141	    }
142	
143	    /**
144	     * Retrieves playerRecords by player ID.
145	     * @param playerId - The ID of the player.
146	     * @returns A promise that resolves to an array of playerRecords or null.
147	     * @throws An error if there is a failure.
148	     */
149	    async getByPlayer(playerId: number): Promise<PlayerRecordType[]> {
150	        return prisma.playerRecord.findMany({
151	            where: {
152	                playerId: playerId,
153	            },
154	        });
155	    }
156	
157	    /**
158	     * Retrieves a player record for a specific year and player.
159	     * @param year - The year of the player record.
160	     * @param playerId - The ID of the player.
161	     * @returns A promise that resolves to the player record for the specified
162	     * year and player, or null if not found.
163	     * @throws If there was an error fetching the player record.
164	     */
165	    async getForYearByPlayer(
166	        year: number,
167	        playerId: number,
168	    ): Promise<PlayerRecordType | null> {
169	        const result = await prisma.playerRecord.findFirst({
170	            where: {
171	                year: year,
172	                playerId: playerId,
173	            },
174	            orderBy: {
175	                gameDayId: 'desc',
176	            },
177	        });
178	
179	        if (result === null) {
180	            const player = await prisma.player.findUnique({
181	                where: {
182	                    id: playerId,
183	                },
184	            });
185	
186	            if (player === null) return null;
187	
188	            return {
189	                id: 0,
190	                playerId: playerId,
191	                year: year,
192	                gamesPlayed: 0,
193	                gameDayId: 0,
194	                responses: 0,
195	                played: 0,
196	                won: 0,
197	                drawn: 0,
198	                lost: 0,
199	                points: 0,
200	                averages: 0,
201	                stalwart: 0,
202	                pub: 0,
203	                rankPoints: null,
204	                rankAverages: null,
205	                rankAveragesUnqualified: null,
206	                rankStalwart: null,
207	                rankSpeedy: null,
208	                rankSpeedyUnqualified: null,
209	                rankPub: null,
210	                speedy: 0,
211	            };
212	        }
213	        else {
214	            return result;
215	        }
216	    }
217	
218	    /**
219	     * Retrieves the list of player records who achieved first place in a given table and year.
220	     *
221	     * This method queries the database for player records where the specified rank column equals 1,
222	     * optionally filtered by year and/or player ID. It further filters the results to include only
223	     * those records whose game day IDs are considered "season enders" as determined by the gameDayService.
224	     *
225	     * @param table - The name of the table to query for winners (used to determine the rank column).
226	     * @param year - (Optional) The year to filter the records by. If not provided, all years greater than 0 are considered.
227	     * @param player - (Optional) The player ID to filter the records by. If not provided, all players are considered.
228	     * @returns A promise that resolves to an array of player records who achieved first place on season-ending game days.
229	     * @throws Will log and rethrow any errors encountered during the database query or filtering process.
230	     */
231	    async getWinners(
232	        table: TableName,
233	        year?: number,
234	        player?: number,
235	    ): Promise<PlayerRecordDataType[]> {
236	        const rank = rankMap[table][0];
237	        const seasonEnders = await gameDayService.getSeasonEnders();
238	        const firstPlaceRecords = await prisma.playerRecord.findMany({
239	            where: {
240	                ...(year ? { year } : { year: { gt: 0 } }),
241	                ...(player ? { playerId: player } : {}),
242	                [rank]: 1,
243	            },
244	            orderBy: {
245	                year: 'desc',
246	            },
247	            include: {
248	                player: true,
249	            },
250	        });
251	
252	        return firstPlaceRecords.filter((record) => seasonEnders.includes(record.gameDayId));
253	    }
254	
255	    /**
256	     * Retrieves player records from the specified table for a given year.
257	     * @param table - The table to retrieve player records from.
258	     * @param year - The year for which to retrieve player records.
259	     * @param qualified - Flag indicating whether to exclude unqualified rows -
260	     * e.g. players who haven't played enough games for the averages table
261	     * (optional). If this is not set, all players are included.
262	     * @param take - The maximum number of player records to retrieve
263	     * (optional).
264	     * @returns A promise that resolves to an array of PlayerRecord objects.
265	     * @throws If there is an error while fetching the player records.
266	     */
267	    async getTable(
268	        table: TableName,
269	        year: number,
270	        qualified?: boolean,
271	        take?: number,
272	    ): Promise<PlayerRecordDataType[]> {
273	        const tableRecord = await prisma.playerRecord.findFirst({
274	            where: {
275	                year: year,
276	                [table]: {
277	                    not: null,
278	                },
279	            },
280	            orderBy: {
281	                gameDayId: 'desc',
282	            },
283	            select: {
284	                gameDayId: true,
285	            },
286	        });
287	        if (!tableRecord) return [];
288	
289	        const rank = rankMap[table][qualified === false ? 1 : 0];
290	        if (!rank) return [];
291	
292	        return prisma.playerRecord.findMany({
293	            where: {
294	                gameDayId: tableRecord.gameDayId,
295	                year: year,
296	                [rank]: {
297	                    not: null,
298	                },
299	            },
300	            orderBy: {
301	                [rank]: 'asc',
302	            },
303	            take: take,
304	            include: {
305	                player: true,
306	            },
307	        });
308	    }
309	
310	    /**
311	     * Creates a player record from validated write input.
312	     * @param data - Player-record write payload.
313	     * @returns The created player-record row.
314	     */
315	    async create(data: PlayerRecordWriteInput): Promise<PlayerRecordType> {
316	        const writeData = PlayerRecordWriteInputSchema.parse(data);
317	        const args = PlayerRecordCreateOneStrictSchema.parse({ data: writeData });
318	        return prisma.playerRecord.create(args);
319	    }
320	
321	    /**
322	     * Upserts a player record by `(playerId, year, gameDayId)`.
323	     * @param data - Player-record write payload.
324	     * @returns The created or updated player-record row.
325	     */
326	    async upsert(data: PlayerRecordWriteInput): Promise<PlayerRecordType> {
327	        const writeData = PlayerRecordWriteInputSchema.parse(data);
328	        const args = PlayerRecordUpsertOneStrictSchema.parse({
329	            where: {
330	                playerId_year_gameDayId: {
331	                    playerId: writeData.playerId,
332	                    year: writeData.year,
333	                    gameDayId: writeData.gameDayId,
334	                },
335	            },
336	            create: writeData,
337	            update: writeData,
338	        });
339	        return prisma.playerRecord.upsert(args);
340	    }
341	
342	    /**
343	     * Upserts all PlayerRecords for a single GameDay.
344	     * @param gameDayId The ID of the GameDay - if undefined then all GameDays
345	     * are processed.
346	     * @returns A promise that resolves to an array of all the upserted
347	     * PlayerRecords, or null if the upsert failed.
348	     * @throws An error if there is a failure.
349	     */
350	    async upsertForGameDay(gameDayId?: number): Promise<PlayerRecordType[]> {
351	        const today = new Date();
352	        const allTimeOutcomes = await outcomeService.getAllForYear(0);
353	
354	        let gameDays = await gameDayService.getAll();
355	        if (gameDayId) {
356	            gameDays = gameDays.filter(g => g.id === gameDayId);
357	        }
358	
359	        const years = gameDays.map(gd => gd.date.getFullYear());
360	        const distinctYears = Array.from(new Set(years));
361	
362	        const playerRecords: PlayerRecordType[] = [];
363	        const allTimePlayerRecords: Record<number, Partial<PlayerRecordType>> = {};
364	        for (const year of distinctYears) {
365	            const yearPlayerRecords: Record<number, Partial<PlayerRecordType>> = {};
366	            const yearOutcomes = await outcomeService.getAllForYear(year);
367	
368	
369	            for (const gameDay of gameDays) {
370	                if (gameDay.date.getFullYear() !== year || gameDay.date > today) {
371	                    continue;
372	                }
373	
374	
375	                const gameDayOutcomes = await outcomeService.getByGameDay(gameDay.id);
376	
377	                await calculateYearPlayerRecords(
378	                    year,
379	                    yearOutcomes,
380	                    yearPlayerRecords,
381	                    gameDay,
382	                    gameDayOutcomes,
383	                    playerRecords,
384	                );
385	                await calculateYearPlayerRecords(
386	                    0,
387	                    allTimeOutcomes,
388	                    allTimePlayerRecords,
389	                    gameDay,
390	                    gameDayOutcomes,
391	                    playerRecords,
392	                );
393	            }
394	        }
395	
396	        return playerRecords;
397	    }
398	
399	    /**
400	     * Rebuilds PlayerRecords from the provided game day onward.
401	     *
402	     * This is intentionally simple: look up the game day's date, find all game
403	     * days on or after that date, and call `upsertForGameDay` for each in
404	     * ascending order. Returns an empty array if the game day does not exist.
405	     *
406	     * Future game days are excluded because records/standings should only
407	     * reflect completed time periods. Fixtures in the future may already have
408	     * response data, but those should not affect rankings yet.
409	     *
410	     * @param gameDayId - The game day from which records should be rebuilt.
411	     * @returns A promise that resolves to the upserted PlayerRecords.
412	     * @throws Any error thrown by underlying services or database operations if
413	     * rebuilding PlayerRecords fails.
414	     */
415	    async upsertFromGameDay(gameDayId: number): Promise<PlayerRecordType[]> {
416	        const fromGameDay = await gameDayService.get(gameDayId);
417	        if (!fromGameDay) return [];
418	
419	        const today = new Date();
420	        const gameDays = (await gameDayService.getAll({ fromDate: fromGameDay.date }))
421	            // Keep future fixtures out of PlayerRecord calculations until
422	            // their date has passed.
423	            .filter((gameDay) => gameDay.date <= today);
424	
425	        if (gameDays.length === 0) {
426	            return [];
427	        }
428	
429	        const playerRecords: PlayerRecordType[] = [];
430	        for (const gameDay of gameDays) {
431	            const upserted = await this.upsertForGameDay(gameDay.id);
432	            playerRecords.push(...upserted);
433	        }
434	
435	        return playerRecords;
436	    }
437	
438	    /**
439	     * Deletes a PlayerRecord.
440	     * @param playerId - The ID of the Player.
441	     * @param year - The year of the GameDay.
442	     * @param gameDayId - The ID of the GameDay.
443	     * @returns Resolves when deletion handling completes.
444	     * @throws {z.ZodError} If key validation fails.
445	     * @throws {Error} If Prisma delete fails for reasons other than not-found.
446	     */
447	    async delete(playerId: number, year: number, gameDayId: number): Promise<void> {
448	        try {
449	            const where = PlayerRecordWhereUniqueInputObjectSchema.parse({
450	                playerId_year_gameDayId: { playerId, year, gameDayId },
451	            });
452	
453	            await prisma.playerRecord.delete({ where });
454	        } catch (error) {
455	            if (isPrismaNotFoundError(error)) {
456	                return;
457	            }
458	            throw error;
459	        }
460	    }
461	
462	    /**
463	     * Deletes all playerRecords.
464	     * @returns A promise that resolves when all playerRecords are deleted.
465	     */
466	    async deleteAll(): Promise<void> {
467	        await prisma.playerRecord.deleteMany();
468	    }
469	}
