474	/**
475	 * Calculates the player records for a specific year and game day.
476	 *
477	 * @param year - The year for which to calculate the player records.
478	 * @param yearOutcomes - The outcomes for the entire year.
479	 * @param yearPlayerRecords - The player records for the entire year.
480	 * @param gameDay - The game day for which to calculate the player records.
481	 * @param gameDayOutcomes - The outcomes for the specific game day.
482	 * @param playerRecords - The existing player records.
483	 */
484	async function calculateYearPlayerRecords(
485	    year: number,
486	    yearOutcomes: OutcomeType[],
487	    yearPlayerRecords: Record<number, Partial<PlayerRecordType>>,
488	    gameDay: GameDayType,
489	    gameDayOutcomes: OutcomeType[],
490	    playerRecords: PlayerRecordType[],
491	) {
492	    // Start with a list of PlayerRecords, including those for anyone with any
493	    // standing this year. For each one with an outcome this game day, add or
494	    // update the PlayerRecord as appropriate
495	
496	    for (const outcome of gameDayOutcomes) {
497	        yearPlayerRecords[outcome.playerId] = {
498	            ...yearPlayerRecords[outcome.playerId],
499	            ...calculatePlayerRecord(year, gameDay, yearOutcomes, outcome),
500	        };
501	    }
502	
503	    // Update the scores that vary with game day, regardless of whether the
504	    // player played this game (e.g. stalwart score)
505	
506	    const gamesPlayed = await gameDayService.getGamesPlayed(year, gameDay.id);
507	
508	    for (const recordData of Object.values(yearPlayerRecords)) {
509	        recordData.gameDayId = gameDay.id;
510	        recordData.gamesPlayed = gamesPlayed;
511	        if (recordData.played && gamesPlayed > 0) {
512	            recordData.stalwart = Math.round(100.0 * recordData.played / gamesPlayed);
513	        }
514	    }
515	
516	    // Calculate the ranks for the set of PlayerRecords
517	    const pointsArray = Object.values(yearPlayerRecords)
518	        .map(r => r.points)
519	        .filter((p): p is number => p !== null);
520	    pointsArray.sort((a, b) => b - a);
521	
522	    const averagesArray = Object.values(yearPlayerRecords)
523	        .map(r => (r.played && r.played > 0 && r.played >= config.minGamesForAveragesTable ? r.averages : null))
