590	/**
591	 * Calculates the player record for a specific year and game day based on the
592	 * provided outcomes.
593	 * @param year - The year of the player record.
594	 * @param gameDay - The game day for which the player record is calculated.
595	 * @param yearOutcomes - The outcomes for the entire year.
596	 * @param outcome - The outcome for the specific game day.
597	 * @returns A promise that resolves to a partial player record object.
598	 */
599	function calculatePlayerRecord(
600	    year: number,
601	    gameDay: GameDayType,
602	    yearOutcomes: OutcomeType[],
603	    outcome: OutcomeType,
604	): Partial<PlayerRecordType> {
605	    const playerYearOutcomes = yearOutcomes.filter(o => o.playerId === outcome.playerId &&
606	        o.gameDayId <= gameDay.id);
607	    const playerYearRespondedOutcomes = playerYearOutcomes.filter(o => o.response != null);
608	    const playerYearPlayedOutcomes = playerYearOutcomes.filter(o => o.points != null);
609	    const pub = playerYearOutcomes.reduce((acc, o) => acc + (o.pub ?? 0), 0);
610	    const data: Partial<PlayerRecordType> = {
611	        playerId: outcome.playerId,
612	        year: year,
613	        gameDayId: gameDay.id,
614	        responses: playerYearRespondedOutcomes.length,
615	        ...{ pub: pub > 0 ? pub : null },
616	    };
617	
618	    if (playerYearPlayedOutcomes.length > 0) {
619	        data.played = playerYearPlayedOutcomes.length;
620	        data.won = playerYearPlayedOutcomes.filter(o => o.points == 3).length;
621	        data.drawn = playerYearPlayedOutcomes.filter(o => o.points == 1).length;
622	        data.lost = playerYearPlayedOutcomes.filter(o => o.points == 0).length;
623	    }
624	
625	    if (data.played && data.played > 0) {
626	        const totalPoints = playerYearPlayedOutcomes.reduce((acc, o) => acc + (o.points!), 0);
627	        data.points = totalPoints;
628	        data.averages = totalPoints / data.played;
629	    }
630	
631	    const responseIntervals = playerYearOutcomes
632	        .map(o => o.responseInterval)
633	        .filter((num): num is number => num !== null);
634	
635	    if (responseIntervals.length > 0) {
636	        data.speedy = responseIntervals.reduce((acc, ri) => acc + ri, 0) / responseIntervals.length;
637	    }
638	
639	    return data;
640	}
