669	    gameDay: GameDayType,
670	    yearOutcomes: OutcomeType[],
671	    outcome: OutcomeType,
672	): Partial<PlayerRecordType> {
673	    const playerYearOutcomes = yearOutcomes.filter(o => o.playerId === outcome.playerId &&
674	        o.gameDayId <= gameDay.id);
675	    const playerYearRespondedOutcomes = playerYearOutcomes.filter(o => o.response != null);
676	    const playerYearPlayedOutcomes = playerYearOutcomes.filter(o => o.points != null);
677	    const pub = playerYearOutcomes.reduce((acc, o) => acc + (o.pub ?? 0), 0);
678	    const data: Partial<PlayerRecordType> = {
679	        playerId: outcome.playerId,
680	        year: year,
681	        gameDayId: gameDay.id,
682	        responses: playerYearRespondedOutcomes.length,
683	        ...{ pub: pub > 0 ? pub : null },
684	    };
685	
686	    if (playerYearPlayedOutcomes.length > 0) {
687	        data.played = playerYearPlayedOutcomes.length;
688	        data.won = playerYearPlayedOutcomes.filter(o => o.points == 3).length;
689	        data.drawn = playerYearPlayedOutcomes.filter(o => o.points == 1).length;
690	        data.lost = playerYearPlayedOutcomes.filter(o => o.points == 0).length;
691	    }
692	
693	    if (data.played && data.played > 0) {
694	        const totalPoints = playerYearPlayedOutcomes.reduce((acc, o) => acc + (o.points!), 0);
695	        data.points = totalPoints;
696	        data.averages = totalPoints / data.played;
697	    }
698	
699	    const responseIntervals = playerYearOutcomes
700	        .map(o => o.responseInterval)
701	        .filter((num): num is number => num !== null);
702	
703	    if (responseIntervals.length > 0) {
704	        data.speedy = responseIntervals.reduce((acc, ri) => acc + ri, 0) / responseIntervals.length;
705	    }
706	
707	    return data;
708	}
